const searches = [{"query": "AI+Operations+Manager", "location": "India", "geo": "102713980", "label": "AI Ops India", "platform": "linkedin_india"}, {"query": "AI+Project+Manager", "location": "India", "geo": "102713980", "label": "AI PM India", "platform": "linkedin_india"}, {"query": "AI+Customer+Success", "location": "India", "geo": "102713980", "label": "AI CS India", "platform": "linkedin_india"}, {"query": "AI+Strategy", "location": "India", "geo": "102713980", "label": "AI Strategy India", "platform": "linkedin_india"}, {"query": "Customer+Success+Manager", "location": "India", "geo": "102713980", "label": "CSM India", "platform": "linkedin_india"}, {"query": "Project+Manager", "location": "Delhi+NCR", "geo": "90009706", "label": "PM Delhi", "platform": "linkedin_india"}, {"query": "AI+Operations+Manager", "location": "Europe", "geo": "91000002", "label": "AI Ops Europe", "platform": "linkedin_eu"}, {"query": "AI+Customer+Success", "location": "Europe", "geo": "91000002", "label": "AI CS Europe", "platform": "linkedin_eu"}];
const urls = searches.map(s => ({
  url: `https://www.linkedin.com/jobs-guest/jobs/api/seeMoreJobPostings/search?keywords=${s.query}&location=${s.location}&geoId=${s.geo}&f_TPR=r86400&start=0`,
  label: s.label,
  source_platform: s.platform
}));
return urls.map(u => ({ json: u }));

const html = $input.first().json.data || $input.first().json;
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

if (typeof html !== 'string') return [];

// Extract job cards from LinkedIn HTML
const jobMatches = html.match(/data-entity-urn="urn:li:jobPosting:(\d+)"/g) || [];
const titleMatches = html.match(/class="base-search-card__title"[^>]*>([^<]+)</g) || [];
const companyMatches = html.match(/class="base-search-card__subtitle"[^>]*>([^<]+)</g) || [];
const locationMatches = html.match(/class="job-search-card__location"[^>]*>([^<]+)</g) || [];

const jobs = [];
for (let i = 0; i < jobMatches.length; i++) {
  const idMatch = jobMatches[i].match(/(\d+)/);
  if (!idMatch) continue;
  const jobId = idMatch[1];
  const title = titleMatches[i] ? titleMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const company = companyMatches[i] ? companyMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const location = locationMatches[i] ? locationMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  jobs.push({
    job_id: jobId,
    job_title: title,
    company: company,
    location: location,
    job_url: `https://www.linkedin.com/jobs/view/${jobId}`,
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

const fs = require('fs');
const path = require('path');

const cacheDir = 'C:/Users/Dev/Desktop/Job Agents/job-agent/setup/cache';
if (!fs.existsSync(cacheDir)) fs.mkdirSync(cacheDir, { recursive: true });

// Per-platform cache file
const item = $input.first().json;
const platform = item.source_platform || 'unknown';
const cacheFile = path.join(cacheDir, `seen_${platform.replace(/[^a-z0-9_]/gi, '_')}.json`);

let seen = [];
try { seen = JSON.parse(fs.readFileSync(cacheFile, 'utf-8')); } catch (e) {}

const url = item.job_url || item.job_id || '';
if (!url) return [];
if (seen.includes(url)) return []; // Already seen

seen.push(url);
if (seen.length > 5000) seen = seen.slice(-3000);
fs.writeFileSync(cacheFile, JSON.stringify(seen));

return [{ json: item }];

const html = $input.first().json.data || '';
const prev = $('Deduplicate').first().json;

// Extract description text from LinkedIn job posting HTML
const descMatch = html.match(/class="show-more-less-html__markup[^"]*"[^>]*>([\s\S]*?)<\/div>/);
let description = '';
if (descMatch) {
  description = descMatch[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}

if (!description || description.length < 50) {
  description = `${prev.job_title} at ${prev.company}. See full description at: ${prev.job_url}`;
}

return [{ json: { ...prev, description: description.substring(0, 3000) } }];
